:root {
  --bg-color: #f4f7f6;
  --card-bg: #ffffff;
  --primary: #2c3e50;
  --accent: #3498db;
  --text: #333;
  --border: #ddd;
}

body {
  font-family: "Segoe UI", Tahoma, Geneva, Verdana, sans-serif;
  background-color: var(--bg-color);
  color: var(--text);
  margin: 0;
  padding: 20px;
}

header {
  text-align: center;
  margin-bottom: 30px;
  color: var(--primary);
  font-size: 1.3rem;
}

header p {
  margin-top: 0;
  color: #7f8c8d;
  font-size: 1.1rem;
}

.stats-grid {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(200px, 1fr));
  gap: 20px;
  margin-bottom: 20px;
}

.explanation-box {
  background-color: #e8f4f8;
  border-left: 4px solid var(--accent);
  padding: 12px 15px;
  border-radius: 4px;
  margin-bottom: 40px;
  font-size: 0.95rem;
  color: #2c3e50;
}

.card {
  background: var(--card-bg);
  padding: 20px;
  border-radius: 8px;
  box-shadow: 0 4px 6px rgba(0, 0, 0, 0.1);
  text-align: center;
  border-top: 4px solid var(--accent);
}

.card h3 {
  margin: 0;
  font-size: 1rem;
  color: #7f8c8d;
  text-transform: uppercase;
}

.card p {
  font-size: 1.8rem;
  font-weight: bold;
  margin: 10px 0 0;
}

.table-container {
  background: var(--card-bg);
  padding: 20px;
  border-radius: 8px;
  box-shadow: 0 4px 6px rgba(0, 0, 0, 0.1);
  overflow-x: auto;
}

table {
  width: 100%;
  border-collapse: collapse;
  margin-top: 10px;
}

th, td {
  text-align: left;
  padding: 12px;
  border-bottom: 1px solid var(--border);
}

th {
  background-color: #f8f9fa;
  color: var(--primary);
}

.badge {
  padding: 4px 8px;
  border-radius: 4px;
  font-size: 0.95rem;
  font-weight: bold;
  display: inline-block;
}

.badge-exposure {
  background: #d0ebff; /* Light blue background */
  color: #0b7285; /* Deep teal/blue text */
  border: 1px solid #a5d8ff;
}

.badge-critical {
  background: #f8d7da;
  color: #721c24;
  border: 1px solid #f5c6cb;
}

.badge-warning {
  background: #fff3cd;
  color: #856404;
  border: 1px solid #ffeeba;
}

.badge-safe {
  background: #d4edda;
  color: #155724;
  border: 1px solid #c3e6cb;
}

.badge-neutral {
  background: #e2e3e5;
  color: #383d41;
  border: 1px solid #d6d8db;
}

code {
  background: #eee;
  padding: 2px 4px;
  border-radius: 3px;
  font-family: monospace;
  font-size: 0.95rem;
  color: #d63031;
}

