appsmith.onReady(() => {
  appsmith.onModelChange(model => {
    const rawData = model.cookies || {};
    const pathData = rawData.paths || {};
    const crossFileData = rawData.cross_file || {};

    // 1. Summary Metrics from JSON
    const nodes = pathData.nodes || [];
    const boundaryCount = crossFileData.ai_boundaries || 0;
    const taintedCount = crossFileData.tainted_symbols || 0;
    document.getElementById('flow-nodes').innerText = nodes.length;
    document.getElementById('boundary-crossings').innerText = boundaryCount;
    document.getElementById('tainted-symbols').innerText = taintedCount;

    // Helper Function to derive explicit boundary types and data context
    function analyzeContext(nodeType) {
      if (nodeType.includes('llm_call')) return {
        context: 'App External LLM Boundary',
        badge: 'badge-critical',
        weight: 1
      };
      if (nodeType.includes('vector_db') || nodeType.includes('db_write')) return {
        context: 'Data Persistence Sink',
        badge: 'badge-critical',
        weight: 1
      };
      if (nodeType.includes('log')) return {
        context: 'External Egress / Log Sink',
        badge: 'badge-critical',
        weight: 1
      };
      if (nodeType.includes('tool_execution')) return {
        context: 'Agent Tool Execution',
        badge: 'badge-warning',
        weight: 2
      };
      if (nodeType.includes('rag_retrieval')) return {
        context: 'Structured Retrieval',
        badge: 'badge-warning',
        weight: 2
      };
      if (nodeType.includes('prompt_template')) return {
        context: 'Prompt Construction',
        badge: 'badge-exposure',
        weight: 3
      };
      if (nodeType.includes('string_format')) return {
        context: 'String Formatting / User Input',
        badge: 'badge-exposure',
        weight: 3
      };
      if (nodeType.includes('env_var')) return {
        context: 'Environment Source',
        badge: 'badge-safe',
        weight: 4
      };
      return {
        context: 'Internal Node Context',
        badge: 'badge-safe',
        weight: 5
      };
    }

    // 2. Prepare and Sort the Nodes by Computed Severity
    const sortedNodes = nodes.map(node => {
      const analysis = analyzeContext(node.type);
      return {
        ...node,
        analysis
      };
    }).sort((a, b) => a.analysis.weight - b.analysis.weight);

    // 3. Populate Exposure Path Table
    const tbody = document.getElementById('path-table-body');
    tbody.innerHTML = '';
    if (sortedNodes.length === 0) {
      tbody.innerHTML = '<tr><td colspan="4" style="text-align: center;">No active exposure paths detected in this scan.</td></tr>';
      return;
    }
    sortedNodes.forEach(node => {
      const tr = document.createElement('tr');

      // Flow Stage Type
      const tdType = document.createElement('td');
      const flowStage = node.type.split('.')[0].toUpperCase(); // SOURCE, TRANSFORM, AI, SINK
      tdType.innerHTML = `<strong>${flowStage}</strong>`;

      // Component Name
      const tdName = document.createElement('td');
      tdName.innerHTML = `<code>${node.name}</code>`;

      // Boundary & Data Context (Applying spec rules)
      const tdContext = document.createElement('td');
      tdContext.innerHTML = `<span class="badge ${node.analysis.badge}">${node.analysis.context}</span>`;

      // Add a snippet of the code underneath as evidence
      const codeSnippet = node.code.length > 50 ? node.code.substring(0, 50) + "..." : node.code;
      tdContext.innerHTML += `<span class="evidence">${codeSnippet}</span>`;

      // File Location
      const tdLoc = document.createElement('td');
      tdLoc.innerHTML = `<span style="color: #7f8c8d;">${node.file} : L${node.line}</span>`;
      tr.appendChild(tdType);
      tr.appendChild(tdName);
      tr.appendChild(tdContext);
      tr.appendChild(tdLoc);
      tbody.appendChild(tr);
    });
  });
});

